module top_module(
    input clk,
    input load,
    input shift_left,
    input shift_right,
    input reset,
    input [3:0] data_in,
    output [3:0] data_out
);reg [3:0] unused_register;

always @(posedge clk) begin
    if (reset) begin
        unused_register <= 4'b0;
    end else if (load) begin
        unused_register <= data_in;
    end else if (shift_left) begin
        unused_register <= {unused_register[2:0], 1'b0};
    end else if (shift_right) begin
        unused_register <= {1'b0, unused_register[3:1]};
    end
end

assign data_out = unused_register;

endmodule
